import React, { useState } from "react";
import { useSwipeable } from "react-swipeable";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const weatherCondition = "rain"; // Replace with real-time data
  const isDaytime = false;         // Replace with real-time logic

  const cards = [
    { label: "Temperature", value: "36.2°C" },
    { label: "Humidity", value: "70%" },
    { label: "Wind Speed", value: "12 km/h" },
    { label: "UV Index", value: "5 (Moderate)" },
    { label: "Visibility", value: "10 km" },
    { label: "Pressure", value: "1012 hPa" },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  const handlers = useSwipeable({
    onSwipedUp: () => {
      if (currentIndex < cards.length - 1) {
        setCurrentIndex((prev) => prev + 1);
      }
    },
    onSwipedDown: () => {
      if (currentIndex > 0) {
        setCurrentIndex((prev) => prev - 1);
      }
    },
    trackTouch: true,
    trackMouse: true,
  });

  return (
    <div
      {...handlers}
      className="relative flex flex-col items-center justify-center min-h-screen overflow-hidden bg-white dark:bg-black"
    >
      {/* Background GIF Overlay */}
      <WeatherOverlay
        weatherCondition={weatherCondition}
        isDaytime={isDaytime}
      />

      {/* Header */}
      <div className="text-center pt-6 z-10">
        <h1 className="text-4xl font-bold text-gray-800 dark:text-white drop-shadow-md">
          Today in <span className="text-purple-500">Atlanta</span>
        </h1>
        <p className="text-lg text-gray-600 dark:text-white/80 mt-1 capitalize drop-shadow-md">
          {weatherCondition}
        </p>
      </div>

      {/* Flashcard Weather Display */}
      <div className="flex-1 flex items-center justify-center z-10">
  <div className="relative w-[240px] h-[160px]">
    {cards.map((card, index) => (
      <div
        key={index}
        className={`absolute top-0 left-0 w-full h-full transition-all duration-500 ease-in-out ${
          index === currentIndex ? "z-20 opacity-100 scale-100" : "z-0 opacity-0 scale-95"
        } flex flex-col items-center justify-center bg-white/60 backdrop-blur-md rounded-xl shadow-xl`}
      >
        <p className="text-sm font-medium text-gray-600">{card.label}</p>
        <p className="text-2xl font-bold text-gray-800 mt-2">{card.value}</p>
      </div>
    ))}
  </div>
</div>

      {/* Slide Indicator Dots */}
      <div className="flex space-x-2 mt-4 z-10">
        {cards.map((_, idx) => (
          <span
            key={idx}
            className={`w-3 h-3 rounded-full transition-all duration-300 ${
              idx === currentIndex
                ? "bg-purple-500 scale-110"
                : "bg-purple-200 opacity-50"
            }`}
          />
        ))}
      </div>

      {/* Swipe Hint */}
      <div className="text-sm text-white/70 mt-4 z-10">
        Swipe up/down to see more
      </div>

      {/* Bottom Navigation */}
      <div className="h-20 fixed bottom-0 left-0 w-full bg-white/30 backdrop-blur-md border-t border-white/40 shadow-lg z-10 flex items-center justify-around rounded-t-2xl">
        {[
          { icon: "🌤", label: "Forecast" },
          { icon: "📡", label: "Radar" },
          { icon: "💬", label: "Community" },
          { icon: "🤖", label: "Weathy" },
        ].map((tab, idx) => (
          <button
            key={idx}
            className="flex flex-col items-center text-gray-700 hover:text-purple-500 transition duration-300"
          >
            <span className="text-xl">{tab.icon}</span>
            <span className="text-xs">{tab.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
